#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e1 + 5;
int t;
int a[MAXN][MAXN], n, m, ans, sum;
bool v[MAXN][MAXN];
void dfs(int x, int y)
{
	if (y > m)
	{
		++x;
		y = 1;
	}
	if (x > n)
	{
		return;
	}
	dfs(x, y + 1);
	if (!v[x - 1][y - 1] && !v[x - 1][y] && !v[x - 1][y + 1] && !v[x][y - 1])
	{
		v[x][y] = 1;
		sum += a[x][y];
		ans = max(ans, sum);
		dfs(x, y + 1);
		sum -= a[x][y];
		v[x][y] = 0;
	}
	v[x][y] = 0;
	return;
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);

	cin >> t;
	while (t--)
	{
		ans=0;
		cin >> n >> m;
		for (int i = 1; i <= n; ++i)
		{
			for (int j = 1; j <= m; ++j)
			{
				cin >> a[i][j];
			}
		}
		for (int i = 1; i <= n; ++i)
		{
			for (int j = 1; j <= m; ++j)
			{
				dfs(i, j);
			}
		}
		cout << ans << '\n';
	}
	return false;
}
